const rawItems = $input.all();

function getText(prop) {
  if (!prop) return '';
  if (prop.type === 'title') return (prop.title || []).map(t => t.plain_text || '').join('');
  if (prop.type === 'rich_text') return (prop.rich_text || []).map(t => t.plain_text || '').join('');
  if (prop.type === 'select') return prop.select?.name || '';
  if (prop.type === 'url') return prop.url || '';
  if (prop.type === 'number') return prop.number ?? '';
  if (prop.type === 'checkbox') return prop.checkbox || false;
  return '';
}

const pages = rawItems.map((item, index) => {
  const props = item.json.properties || {};
  const pageId = getText(props['頁面代碼']) || item.json.id || `page-${index + 1}`;
  const pageType = getText(props['頁面類型']) || 'section';
  const externalUrl = getText(props['外部連結']);

  return {
    id: pageId,
    title: getText(props['頁面名稱']),
    slug: externalUrl || pageId,
    parent_id: getText(props['父層頁面ID']) || null,
    sort_order: Number(getText(props['排序']) || ((index + 1) * 10)),
    is_visible: getText(props['是否顯示']) !== false,
    page_type: pageType,
    template_key: getText(props['模板代碼']) || pageType,
    nav_label: getText(props['導覽名稱']) || getText(props['頁面名稱']),
    nav_icon: getText(props['導覽圖示']),
    seo_title: getText(props['SEO標題']),
    seo_description: getText(props['SEO描述'])
  };
}).filter(page => page.title && page.is_visible);

const byId = new Map(pages.map(page => [page.id, { ...page, children: [] }]));
const roots = [];

pages.sort((a, b) => a.sort_order - b.sort_order).forEach(page => {
  const item = byId.get(page.id);
  const parent = item.parent_id ? byId.get(item.parent_id) : null;
  if (parent && !parent.parent_id) {
    parent.children.push(item);
  } else {
    item.parent_id = null;
    roots.push(item);
  }
});

roots.forEach(root => root.children.sort((a, b) => a.sort_order - b.sort_order));
roots.sort((a, b) => a.sort_order - b.sort_order);

return [{ json: { success: true, total: pages.length, maxDepth: 2, pages, tree: roots } }];
